def clean_row(line):
    name, score, email = line.strip().split(",")
    return {"name": name.strip().title(), "score": int(score), "email": email.strip().lower()}

records = []
with open("data/roster.csv") as file:
    next(file)
    for line in file:
        # TODO: use try/except to skip bad rows.
        records.append(clean_row(line))

print(records)

cp-4-move-cleaning-to-module.starterCode:
from tools.cleaning import clean_row

records = []
with open("data/roster.csv") as file:
    next(file)
    for line in file:
        try:
            records.append(clean_row(line))
        except ValueError:
            continue

print(records)
